int array_all_zero(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      ((__return == 1 &&
        (forall (i: Z), (0 <= i && i < n) => l[i] == 0)) ||
       (__return == 0 &&
        (exists i, 0 <= i && i < n && l[i] != 0))) &&
      IntArray::full(a, n, l)
*/
{
    int i;

    /*@ Inv
          0 <= i && i <= n &&
          a == a@pre &&
          n == n@pre &&
          (forall (j: Z), (0 <= j && j < i) => l[j] == 0) &&
          IntArray::full(a, n, l)
    */
    for (i = 0; i < n; ++i) {
        if (a[i] != 0) {
            return 0;
        }
    }

    /*@ Assert
          i == n &&
          a == a@pre &&
          n == n@pre &&
          (forall (j: Z), (0 <= j && j < n) => l[j] == 0) &&
          IntArray::full(a, n, l)
    */
    return 1;
}

